//! Ackermann Runtime Certification Kernel
//! =======================================
//!
//! Rust mirror of `Gnosis.AckermannRuntimeCertificate` (see
//! `open-source/gnosis-math/Gnosis/AckermannRuntimeCertificate.lean`,
//! sibling — being written in parallel).
//!
//! ## What it does
//!
//! Pins the five Lean oracle values for `ackermannDiag` (the diagonal
//! of the hyperoperation hierarchy from `AckermannFunction.lean`) and
//! computes the percentile `T(n) * 100 / ackermannDiag(n)` for an
//! instrumented callable on the calibration window n ∈ {0, 1, 2, 3}.
//! The Lean oracle pentad it mirrors:
//!
//! - `ackermannCeiling 0 = 1`
//! - `ackermannCeiling 1 = 2`
//! - `ackermannCeiling 2 = 4`
//! - `ackermannCeiling 3 = 27`
//! - `ackermannCeiling 4 = hyperop 4 4 4` (astronomical, no numeric
//!   Rust contract — `ackermann_ceiling(4)` returns `None`)
//!
//! ## What it does NOT do
//!
//! - measure wall-clock; the metric is step counts, not seconds
//! - certify n ≥ 4 numerically; n=4 ceiling is astronomical, the kernel
//!   returns a STRUCTURAL "PR-bounded" verdict via finite-difference test

#![allow(dead_code)]

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AckermannCertificate {
    pub n: u32,
    pub steps: u64,
    pub ceiling: u64,
    pub percentile: u32, // truncated; (steps * 100) / ceiling
}

/// Mirror of Lean `ackermannCeiling`. Returns `Some(v)` for n ≤ 3 with
/// the exact value pinned by `AckermannRuntimeOracle`; returns `None`
/// for n ≥ 4 — structural-fallback regime, no numeric ceiling.
pub fn ackermann_ceiling(n: u32) -> Option<u64> {
    match n {
        0 => Some(1),
        1 => Some(2),
        2 => Some(4),
        3 => Some(27),
        _ => None,
    }
}

/// Compute the percentile for a measured step count against the ceiling.
/// Returns `None` if the ceiling is undefined (n ≥ 4).
pub fn percentile(steps: u64, n: u32) -> Option<u32> {
    let ceiling = ackermann_ceiling(n)?;
    Some(((steps.saturating_mul(100)) / ceiling) as u32)
}

/// Certify a runtime over the calibration window n ∈ [0, max_n].
/// For each n ≤ 3 it computes a numeric `AckermannCertificate`; for
/// n ≥ 4 it skips (returns no entry — caller should use the structural
/// PR-bound fallback).
pub fn certify<F>(target: F, max_n: u32) -> Vec<AckermannCertificate>
where
    F: Fn(u32) -> u64,
{
    let mut out = Vec::new();
    for n in 0..=max_n.min(3) {
        let steps = target(n);
        let ceiling = ackermann_ceiling(n).expect("n ≤ 3 has a ceiling");
        let pct = ((steps.saturating_mul(100)) / ceiling) as u32;
        out.push(AckermannCertificate {
            n,
            steps,
            ceiling,
            percentile: pct,
        });
    }
    out
}

/// Structural PR-bound fallback: a finite-difference test on `target`
/// over a small sample. Returns `Some(degree)` if the target appears
/// polynomial of that degree (the (degree+1)-th forward difference
/// vanishes). Returns `None` if no PR-polynomial envelope fits up to
/// degree 3 — the honest "super-polynomial / refuse to certify" verdict.
///
/// Why finite differences: a polynomial of degree d has its (d+1)-th
/// forward difference identically zero, so the test is exact for
/// polynomial targets and rejects anything growing strictly faster
/// (exponential, factorial, Ackermann-class) by construction. The Lean
/// side proves the structural separation only at the calibration
/// window; this fallback never claims certification without
/// finite-difference evidence on the SAMPLED window.
///
/// Calibration: requires `sample_size >= 5` so the degree-3 check has
/// at least one (d=4) - (d=3) comparison; smaller samples return None.
pub fn polynomial_degree_estimate<F>(target: F, sample_size: u32) -> Option<u32>
where
    F: Fn(u32) -> u64,
{
    if sample_size < 5 {
        return None;
    }
    let samples: Vec<i128> = (0..sample_size).map(|n| target(n) as i128).collect();
    let d1: Vec<i128> = samples.windows(2).map(|w| w[1] - w[0]).collect();
    let d2: Vec<i128> = d1.windows(2).map(|w| w[1] - w[0]).collect();
    let d3: Vec<i128> = d2.windows(2).map(|w| w[1] - w[0]).collect();
    let d4: Vec<i128> = d3.windows(2).map(|w| w[1] - w[0]).collect();

    // Polynomial of degree d ⇒ d_(d+1) is identically zero.
    if d1.iter().all(|&x| x == 0) {
        Some(0) // constant
    } else if d2.iter().all(|&x| x == 0) {
        Some(1) // linear
    } else if d3.iter().all(|&x| x == 0) {
        Some(2) // quadratic
    } else if d4.iter().all(|&x| x == 0) {
        Some(3) // cubic
    } else {
        None // super-polynomial — refuse to certify
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Pin all five Lean oracle values exactly: ceiling(0..3) returns
    /// Some([1, 2, 4, 27]); ceiling(4) returns None.
    /// Mirrors `AckermannFunction.lean::ack_0/ack_1/ack_2/ack_3` and the
    /// structural-fallback contract for n ≥ 4.
    #[test]
    fn ackermann_ceiling_pentad_parity() {
        assert_eq!(ackermann_ceiling(0), Some(1));
        assert_eq!(ackermann_ceiling(1), Some(2));
        assert_eq!(ackermann_ceiling(2), Some(4));
        assert_eq!(ackermann_ceiling(3), Some(27));
        assert_eq!(ackermann_ceiling(4), None);
    }

    /// Zero step-count target ⇒ all percentiles are 0.
    #[test]
    fn zero_runtime_is_zero_percent() {
        let certs = certify(|_| 0, 3);
        assert_eq!(certs.len(), 4);
        for c in &certs {
            assert_eq!(c.percentile, 0, "n={} got pct={}", c.n, c.percentile);
            assert_eq!(c.steps, 0);
        }
    }

    /// A target whose step count IS the ceiling saturates at 100% across
    /// the whole calibration window.
    #[test]
    fn ackermann_self_is_100_percent() {
        let certs = certify(|n| ackermann_ceiling(n).unwrap(), 3);
        assert_eq!(certs.len(), 4);
        for c in &certs {
            assert_eq!(c.percentile, 100, "n={} got pct={}", c.n, c.percentile);
            assert_eq!(c.steps, c.ceiling);
        }
    }

    /// Identity target T(n) = n exercises the PR-bound percentile calc:
    /// n=0 ⇒ 0/1 = 0%, n=1 ⇒ 100/2 = 50%, n=2 ⇒ 200/4 = 50%,
    /// n=3 ⇒ 300/27 = 11% (integer truncated). Matches the Lean
    /// PR-bound calc on the calibration window.
    #[test]
    fn identity_runtime_calibration_window() {
        let certs = certify(|n| n as u64, 3);
        assert_eq!(certs.len(), 4);
        assert_eq!(certs[0].percentile, 0);
        assert_eq!(certs[1].percentile, 50);
        assert_eq!(certs[2].percentile, 50);
        assert_eq!(certs[3].percentile, 11);
    }

    /// Finite-difference detector pins polynomial degree for linear,
    /// quadratic, and cubic targets on a 5-sample window. The detector
    /// is exact (not heuristic) because a polynomial of degree d has
    /// its (d+1)-th forward difference identically zero — see kernel
    /// doc comment on `polynomial_degree_estimate`. Calibration window
    /// `sample_size = 5` is the minimum that exercises the d=3 path
    /// (need d4 to have at least one element).
    #[test]
    fn polynomial_degree_estimate_detects_linear_quadratic_cubic() {
        assert_eq!(polynomial_degree_estimate(|n| n as u64, 5), Some(1));
        assert_eq!(
            polynomial_degree_estimate(|n| (n as u64) * (n as u64), 5),
            Some(2)
        );
        assert_eq!(
            polynomial_degree_estimate(|n| (n as u64) * (n as u64) * (n as u64), 5),
            Some(3)
        );
    }

    /// Exponential target 2^n must FAIL the polynomial envelope test up
    /// to degree 3. Sampling at sample_size=6 ⇒ d4 = [1, 2, 4] is
    /// non-zero, so the detector returns None ("super-polynomial,
    /// refuse to certify"). This is the honest verdict for the n ≥ 4
    /// regime.
    #[test]
    fn polynomial_degree_estimate_rejects_exponential() {
        assert_eq!(polynomial_degree_estimate(|n| 1u64 << n, 6), None);
    }

    /// max_n is clamped to 3 — the calibration window is the four-point
    /// pentad-minus-fallback {0, 1, 2, 3}. Asking for max_n=10 must NOT
    /// produce entries for n ∈ {4..10}; those are the structural-
    /// fallback regime, not numeric.
    #[test]
    fn certify_max_n_clamped_to_three() {
        let certs = certify(|n| n as u64, 10);
        assert_eq!(certs.len(), 4);
        assert_eq!(certs[0].n, 0);
        assert_eq!(certs[3].n, 3);
    }
}
